import{_ as d,c as e,o,aN as a}from"./chunks/framework.CqA5BTDU.js";const c="/kb/assets/n9e-datasource-detail-bottom-annotated.CtS7HRRV.png",r="/kb/assets/n9e-template-linux-dashboard-list-annotated.leZEKbDo.png",i="/kb/assets/n9e-template-import-business-group-annotated.Dcg216jP.png",s="/kb/assets/n9e-dashboard-host-table-data-annotated.D2MQ_WNN.png",p="/kb/assets/n9e-dashboard-custom-panel-config-annotated.CUtmm6Qj.png",l="/kb/assets/n9e-alert-rule-promql-config-annotated.BAiOmjL2.png",n="/kb/assets/n9e-alert-event-detail-promql-annotated.CGkVS1C8.png",P=JSON.parse('{"title":"Nightingale平台操作","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/22-Nightingale平台操作.md","filePath":"12.可观测性与监控告警/22-Nightingale平台操作.md","lastUpdated":null}'),h={name:"12.可观测性与监控告警/22-Nightingale平台操作.md"};function b(u,t,g,m,E,q){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="nightingale平台操作" tabindex="-1">Nightingale平台操作 <a class="header-anchor" href="#nightingale平台操作" aria-label="Permalink to &quot;Nightingale平台操作&quot;">​</a></h1><p>Nightingale 的控制台操作主要围绕数据源、业务组、Dashboard、告警规则和告警事件展开。基础部署跑起来以后，真正要确认的是三件事：N9E 能查到后端时序库，Dashboard 能把采集到的主机指标展示出来，告警规则能生成可追踪的事件。</p><p>Nightingale 是监控告警平台，负责把采集器、时序库、看板、告警规则、通知策略和事件处理放到同一个控制台里。它本身不等同于时序数据库；当前实验里，指标由 Categraf 上报，数据落到 VictoriaMetrics，N9E 负责查询、展示、规则计算和事件管理。</p><p>N9E 在实验环境中作为监控平台入口，控制台能访问只说明服务已经启动，平台可用性主要看数据源接入、模板复用、规则管理、事件处理和通知链路。</p><h2 id="一、平台操作链路" tabindex="-1">一、平台操作链路 <a class="header-anchor" href="#一、平台操作链路" aria-label="Permalink to &quot;一、平台操作链路&quot;">​</a></h2><p>当前实验环境里，Categraf 采集主机指标，N9E 作为平台入口，VictoriaMetrics 保存时序数据，N9E 控制台再基于数据源做查询、看板和告警。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20node12%5B%22%E8%A2%AB%E7%9B%91%E6%8E%A7%E8%8A%82%E7%82%B9%20node12%3Cbr%2F%3ECategraf%22%5D%20--%3E%20n9e%5B%22N9E%20%E5%B9%B3%E5%8F%B0%3Cbr%2F%3E%E6%8E%A5%E6%94%B6%E4%B8%8A%E6%8A%A5%20%2F%20%E7%AE%A1%E7%90%86%E8%A7%84%E5%88%99%22%5D%0A%20%20%20%20node13%5B%22%E8%A2%AB%E7%9B%91%E6%8E%A7%E8%8A%82%E7%82%B9%20node13%3Cbr%2F%3ECategraf%22%5D%20--%3E%20n9e%0A%20%20%20%20n9e%20--%3E%20vm%5B%22VictoriaMetrics%3Cbr%2F%3EPromQL%20%E6%9F%A5%E8%AF%A2%20%2F%20remote_write%20%E5%AD%98%E5%82%A8%22%5D%0A%20%20%20%20n9e%20--%3E%20dashboard%5B%22Dashboard%3Cbr%2F%3E%E6%A8%A1%E6%9D%BF%20%2F%20%E8%87%AA%E5%BB%BA%E9%9D%A2%E6%9D%BF%22%5D%0A%20%20%20%20n9e%20--%3E%20alert%5B%22%E5%91%8A%E8%AD%A6%E8%A7%84%E5%88%99%3Cbr%2F%3EPromQL%20%2F%20%E7%BA%A7%E5%88%AB%20%2F%20%E6%8C%81%E7%BB%AD%E6%97%B6%E9%97%B4%22%5D%0A%20%20%20%20alert%20--%3E%20event%5B%22%E5%91%8A%E8%AD%A6%E4%BA%8B%E4%BB%B6%3Cbr%2F%3ETriggered%20%2F%20Recovered%20%2F%20%E5%B1%8F%E8%94%BD%22%5D%0A"></div><p>几个对象的关系如下：</p><table tabindex="0"><thead><tr><th>对象</th><th>作用</th><th>平台里容易看错的点</th></tr></thead><tbody><tr><td>数据源</td><td>告诉 N9E 到哪里查询指标</td><td>它不是&quot;指标本身&quot;，只是查询和告警的后端连接</td></tr><tr><td>业务组</td><td>管理 Dashboard、规则、人员和权限归属</td><td>模板导入后要落到具体业务组</td></tr><tr><td>Dashboard</td><td>展示时序数据和表格数据</td><td>变量和数据源没选对时，看板会是空的</td></tr><tr><td>告警规则</td><td>定期执行查询并判断是否触发</td><td>PromQL、数据源、级别、持续时间缺一块都容易失效</td></tr><tr><td>告警事件</td><td>规则触发后的结果记录</td><td>排查时主要看标签、当前值、触发时间和状态</td></tr></tbody></table><p>业务组是 N9E 里的管理范围，同一组下面放 Dashboard、告警规则、用户权限和接收人。实验环境只有 <code>Default Busi Group</code>，生产里通常按业务线、环境或团队划分。</p><h2 id="二、数据源接入" tabindex="-1">二、数据源接入 <a class="header-anchor" href="#二、数据源接入" aria-label="Permalink to &quot;二、数据源接入&quot;">​</a></h2><p>数据源回答的是&quot;N9E 从哪里查指标&quot;。当前实验使用 <code>Prometheus</code> 类型接入 VictoriaMetrics，名称为 <code>VictoriaMetrics</code>。这里的 <code>Prometheus</code> 类型指兼容 Prometheus 查询接口的数据源，N9E 可以用 PromQL 查询它；VictoriaMetrics、Mimir、Thanos 这类时序库都常按这个方式接入。</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>数据源类型</td><td><code>Prometheus</code></td><td>VictoriaMetrics 兼容 Prometheus 查询协议</td></tr><tr><td>数据源名称</td><td><code>VictoriaMetrics</code></td><td>Dashboard 和告警规则里会用这个名字</td></tr><tr><td>查询 URL</td><td><code>http://victoriametrics:8428</code></td><td>N9E 容器访问 VictoriaMetrics 的地址</td></tr><tr><td>Remote Write URL</td><td><code>http://victoriametrics:8428/api/v1/write</code></td><td>指标写入地址</td></tr><tr><td>告警引擎集群</td><td><code>default</code></td><td>规则计算由这个集群里的告警引擎执行</td></tr></tbody></table><p>控制台里的数据源入口如下：</p><p><code>集成中心 -&gt; 数据源 -&gt; 创建 / 编辑</code> （英文含义：Integration Center -&gt; Data sources -&gt; Create / Edit）</p><p>操作步骤：</p><ol><li>进入 <code>集成中心 -&gt; 数据源</code>，点击创建数据源；已有数据源时点击 <code>VictoriaMetrics</code> 进入详情，再点 <code>编辑</code>。</li><li>数据源类型选择 <code>Prometheus</code>。</li><li>填写查询 URL、Remote Write URL 和告警引擎集群。</li><li>保存后回到数据源列表，确认 <code>VictoriaMetrics</code> 出现在列表中。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>数据源类型</td><td><code>Prometheus</code></td><td>表示兼容 Prometheus 查询协议</td></tr><tr><td>数据源名称</td><td><code>VictoriaMetrics</code></td><td>Dashboard 和告警规则里会引用这个名字</td></tr><tr><td>URL</td><td><code>http://victoriametrics:8428</code></td><td>N9E 容器内访问 VictoriaMetrics 的查询地址</td></tr><tr><td>Remote Write URL</td><td><code>http://victoriametrics:8428/api/v1/write</code></td><td>N9E 转写指标到 VictoriaMetrics 的写入地址</td></tr><tr><td>时序库内网地址</td><td><code>http://victoriametrics:8428</code></td><td>平台内部访问时序库的地址</td></tr><tr><td>告警引擎集群</td><td><code>default</code></td><td>规则计算使用的告警引擎集群</td></tr></tbody></table><p><img src="'+c+`" alt="N9E 数据源详情"></p><p>保存后验证：</p><p>进入 <code>数据查询 -&gt; 指标</code> （英文含义：Data query -&gt; Metrics），选择 <code>VictoriaMetrics</code> 数据源，执行 <code>cpu_usage_active{ident=&quot;node12&quot;}</code>。能返回曲线或表格数据，说明 N9E 已经能查到后端时序库。</p><p>排错入口：</p><p>数据源保存失败时看页面校验提示；保存成功但查询无数据时，在 N9E 所在机器上访问 VictoriaMetrics API，再检查容器网络里的 <code>victoriametrics:8428</code> 是否可达。地址视角很关键，浏览器能访问 <code>192.168.10.11:8428</code> 不代表 N9E 容器里也能用这个地址。</p><p>数据源详情里重点看 URL、Remote Write 和告警引擎集群这几处配置。N9E 和 VictoriaMetrics 在同一个 Compose 网络里，所以地址写容器服务名 <code>victoriametrics</code>，不是浏览器访问用的 <code>192.168.10.11</code>。</p><p>后端也可以直接查一次指标，确认不是页面显示问题：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 VictoriaMetrics 所在机器上执行，确认 node12 已经写入主机指标</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -G</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --data-urlencode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;query=cpu_usage_active{ident=&quot;node12&quot;}&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  http://127.0.0.1:8428/api/v1/query</span></span></code></pre></div><p>数据源配置最容易错在&quot;地址视角&quot;。浏览器能访问 <code>192.168.10.11:8428</code>，不代表 N9E 容器里也能用这个地址；容器内通常用服务名，物理机部署才常见 <code>127.0.0.1</code> 或内网 IP。</p><h2 id="三、模板中心导入-dashboard" tabindex="-1">三、模板中心导入 Dashboard <a class="header-anchor" href="#三、模板中心导入-dashboard" aria-label="Permalink to &quot;三、模板中心导入 Dashboard&quot;">​</a></h2><p>模板中心里的 Dashboard 需要导入到业务组，才会出现在自己的仪表盘列表里。Linux 分类里内置了 Categraf 和 Node Exporter 两类模板，当前采集端是 Categraf，所以选择带 <code>Categraf</code> 标签的模板。</p><p>模板中心入口如下：</p><p><code>集成中心 -&gt; 模板中心 -&gt; Linux -&gt; 仪表盘</code> （英文含义：Integration Center -&gt; Template Center -&gt; Linux -&gt; Dashboard）</p><p>操作步骤：</p><ol><li>进入 <code>集成中心 -&gt; 模板中心</code>，打开 <code>Linux</code> 分类。</li><li>切到 <code>仪表盘</code> 页签。</li><li>勾选 <code>Host Table NG</code>，确认标签是 <code>Categraf</code>。</li><li>点击 <code>导入业务组</code>。</li></ol><p>模板选择：</p><table tabindex="0"><thead><tr><th>字段 / 位置</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>分类</td><td><code>Linux</code></td><td>主机监控模板所在分类</td></tr><tr><td>页签</td><td><code>仪表盘</code></td><td>导入 Dashboard 模板，不是告警规则模板</td></tr><tr><td>模板名称</td><td><code>Host Table NG</code></td><td>主机表格型 Dashboard</td></tr><tr><td>标签</td><td><code>Categraf</code></td><td>当前实验采集端是 Categraf，所以选 Categraf 模板</td></tr></tbody></table><p>模板列表里重点确认模板类型、<code>Categraf</code> 标签和&quot;导入业务组&quot;入口，导入失败或模板选错时可以对照这三处。</p><p><img src="`+r+'" alt="Linux Dashboard 模板"></p><p>导入弹窗里选择目标业务组：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>目标业务组</td><td><code>Default Busi Group</code></td><td>Dashboard 导入后的归属业务组</td></tr><tr><td>模板 JSON 内容</td><td>保持默认</td><td>模板内已有变量、Panel、PromQL 和表格字段</td></tr></tbody></table><p>操作步骤：</p><ol><li>在 <code>导入业务组</code> 弹窗里选择 <code>Default Busi Group</code>。</li><li>模板 JSON 内容保持默认。</li><li>点击确认导入。</li></ol><p><img src="'+i+'" alt="导入业务组"></p><p>保存后验证：</p><p>进入 <code>数据查询 -&gt; 仪表盘</code> （英文含义：Data query -&gt; Dashboards），列表里出现 <code>Host Table NG</code>，说明模板已经进入业务组。弹窗里的 JSON 是模板内容，包含变量、面板、PromQL 和表格字段等配置。平台模板导入比手动搭十几个 panel 更适合做第一版主机看板。</p><p>导入完成后，仪表盘列表里会出现 <code>Host Table NG</code>，分类标签是 <code>Categraf</code>。这一步说明模板已经变成当前业务组里的 Dashboard。</p><h2 id="四、dashboard-验证" tabindex="-1">四、Dashboard 验证 <a class="header-anchor" href="#四、dashboard-验证" aria-label="Permalink to &quot;四、Dashboard 验证&quot;">​</a></h2><p>打开 Dashboard 的路径如下：</p><p><code>数据查询 -&gt; 仪表盘 -&gt; Host Table NG</code> （英文含义：Data query -&gt; Dashboards -&gt; Host Table NG）</p><p>操作步骤：</p><ol><li>进入 <code>数据查询 -&gt; 仪表盘</code>。</li><li>打开 <code>Host Table NG</code>。</li><li>顶部变量 <code>PROM</code> 选择 <code>VictoriaMetrics</code>。</li><li>机器变量选择 <code>All</code>。</li><li>时间范围选择最近 1 小时。</li></ol><p>保存后验证：</p><p>表格里能看到 <code>node12</code>、<code>node13</code> 和 <code>categraf01</code>，并且 CPU 利用率、内存利用率、根分区利用率都有当前值。</p><p><img src="'+s+'" alt="导入后的主机看板"></p><p>排错入口：</p><p>看板没有数据时，先看顶部变量 <code>PROM</code> 是否选中 <code>VictoriaMetrics</code>，再看 <code>ident</code> 是否为空。变量正常但表格为空时，进入 <code>数据查询 -&gt; 指标</code> 执行模板里用到的 PromQL；指标查询也为空，再回到 VictoriaMetrics API 和 Categraf 日志检查上报链路。</p><p>导入后的看板要能查到真实指标：数据源选中后，主机行、CPU、内存、根分区利用率都有实际值。</p><p>Dashboard 里常见的变量：</p><table tabindex="0"><thead><tr><th>变量</th><th>当前值</th><th>作用</th></tr></thead><tbody><tr><td><code>PROM</code></td><td><code>VictoriaMetrics</code></td><td>选择查询哪个 Prometheus Like 数据源</td></tr><tr><td><code>ident</code></td><td><code>All</code></td><td>选择主机标识，来自指标标签</td></tr></tbody></table><p>如果模板导入后没有数据，排查顺序通常是：数据源是否选对，时间范围是否覆盖最近数据，变量 <code>ident</code> 是否有值，PromQL 里用到的指标名是否和当前采集器一致。Categraf 和 Node Exporter 的指标名并不完全一样，模板选错时页面可能没有任何报错，只是没有曲线。</p><h2 id="五、自建面板" tabindex="-1">五、自建面板 <a class="header-anchor" href="#五、自建面板" aria-label="Permalink to &quot;五、自建面板&quot;">​</a></h2><p>模板能快速出图，但日常排查经常需要临时补一个面板。实验里新增一个时序图面板，标题是 <code>主机 CPU 使用率</code>，查询语句如下：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cpu_usage_active{ident=~&quot;$ident&quot;}</span></span></code></pre></div><p>这里用 <code>ident=~&quot;$ident&quot;</code> 是为了复用 Dashboard 变量。变量选择 <code>All</code> 时可以看所有机器，切到单台机器时曲线会跟着收窄。通用看板里保留变量比写死主机名更灵活——写死主机名适合临时排查，不适合沉淀成共享看板。</p><p>PromQL 是 Prometheus 查询语言，这里用它从 VictoriaMetrics 取时间序列。N9E 的 Dashboard 和告警都依赖 PromQL，只是 Dashboard 把结果画成图，告警规则把结果拿去做阈值判断。</p><p>添加 Panel 的路径如下：</p><p><code>数据查询 -&gt; 仪表盘 -&gt; Host Table NG -&gt; 添加图表</code> （英文含义：Data query -&gt; Dashboards -&gt; Host Table NG -&gt; Add panel）</p><p>操作步骤：</p><ol><li>打开 <code>Host Table NG</code>，点击右上角 <code>添加图表</code>。</li><li>图表类型选择 <code>时序图</code>。</li><li>顶部变量 <code>PROM</code> 选择 <code>VictoriaMetrics</code>，机器变量保持 <code>All</code>。</li><li>在 PromQL 输入框里填写 <code>cpu_usage_active{ident=~&quot;$ident&quot;}</code>。</li><li>右侧 <code>面板配置</code> 里把标题填成 <code>主机 CPU 使用率</code>。</li><li>左侧预览区出现曲线后，点击 <code>保存</code>。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>说明</th></tr></thead><tbody><tr><td>图表类型</td><td><code>时序图</code></td><td>CPU 使用率适合用时间曲线观察</td></tr><tr><td>数据源变量</td><td><code>VictoriaMetrics</code></td><td>从当前时序库查询数据</td></tr><tr><td>PromQL</td><td><code>cpu_usage_active{ident=~&quot;$ident&quot;}</code></td><td>复用 Dashboard 里的机器变量</td></tr><tr><td>面板标题</td><td><code>主机 CPU 使用率</code></td><td>Dashboard 上显示的名称</td></tr></tbody></table><p><img src="'+p+`" alt="自建 CPU 面板"></p><p>保存后验证：</p><p>保存后回到 Dashboard，新增面板能跟随 <code>ident</code> 变量变化。变量为 <code>All</code> 时显示多台机器，切到 <code>node12</code> 时只显示单台机器。</p><p>排错入口：</p><p>添加面板时左侧预览区没有曲线，直接在同一编辑页检查 PromQL、数据源变量和时间范围。表达式不确定时，进入 <code>数据查询 -&gt; 指标</code> 用同一条 PromQL 查询。</p><p>如果只想看单台机器，可以把表达式改成：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 临时定位单台机器时使用精确匹配，避免变量展开带来干扰</span></span>
<span class="line"><span>cpu_usage_active{ident=&quot;node12&quot;}</span></span></code></pre></div><p>主机 CPU 告警或看板里最好带上 <code>cpu=&quot;cpu-total&quot;</code>，否则某些采集器会同时返回每个 CPU 核心和总计值：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 只看总 CPU 使用率，避免每个核心都生成一条曲线</span></span>
<span class="line"><span>cpu_usage_active{cpu=&quot;cpu-total&quot;, ident=&quot;node12&quot;}</span></span></code></pre></div><h2 id="六、告警规则" tabindex="-1">六、告警规则 <a class="header-anchor" href="#六、告警规则" aria-label="Permalink to &quot;六、告警规则&quot;">​</a></h2><p>N9E 的告警规则由 PromQL、数据源绑定、级别、执行频率和持续时长一起组成。PromQL 负责取数，持续时长负责过滤短暂抖动，级别和标签用于后续通知匹配。</p><table tabindex="0"><thead><tr><th>字段</th><th>当前实验值</th><th>说明</th></tr></thead><tbody><tr><td>规则名称</td><td><code>实验-节点CPU使用率触发</code></td><td>事件列表和通知里会显示</td></tr><tr><td>数据源</td><td><code>VictoriaMetrics</code></td><td>规则从这里查询指标</td></tr><tr><td>PromQL</td><td><code>cpu_usage_active{ident=&quot;node12&quot;} &gt; 0</code></td><td>实验触发用，保证能生成事件</td></tr><tr><td>告警级别</td><td><code>S2（Warning）</code></td><td>当前按普通告警处理</td></tr><tr><td>执行频率</td><td><code>@every 60s</code></td><td>每 60 秒计算一次规则</td></tr><tr><td>持续时长</td><td><code>60</code></td><td>条件持续满足后触发</td></tr><tr><td>附加标签</td><td><code>env=lab</code></td><td>后续可用于事件过滤和通知规则</td></tr></tbody></table><p>实验规则故意写成 <code>&gt; 0</code>，目的是确认规则、告警引擎、事件链路能跑通。真实主机 CPU 告警一般写成类似下面这样：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># CPU 总使用率超过 85% 才触发，避免实验阈值误用到真实环境</span></span>
<span class="line"><span>cpu_usage_active{cpu=&quot;cpu-total&quot;, ident=&quot;node12&quot;} &gt; 85</span></span></code></pre></div><p>告警规则入口如下：</p><p><code>告警 -&gt; 规则管理 -&gt; 创建规则</code> （英文含义：Alerting -&gt; Rule management -&gt; Create rule）</p><p>操作步骤：</p><ol><li>进入 <code>告警 -&gt; 规则管理</code>，点击创建规则。</li><li>业务组选择 <code>Default Busi Group</code>。</li><li>数据源选择 <code>VictoriaMetrics</code>。</li><li>在告警条件里填写 PromQL。</li><li>告警级别选择 <code>二级告警（Warning）</code>。</li><li>执行频率填写 <code>@every 60s</code>，持续时长填写 <code>60</code>。</li><li>事件 relabel 或附加标签里保留 <code>env=lab</code>。</li><li>点击 <code>保存</code>。</li></ol><p>字段填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前实验值</th><th>说明</th></tr></thead><tbody><tr><td>业务组</td><td><code>Default Busi Group</code></td><td>规则归属</td></tr><tr><td>数据源</td><td><code>VictoriaMetrics</code></td><td>规则查询的时序库</td></tr><tr><td>触发表达式</td><td><code>cpu_usage_active{ident=&quot;node12&quot;} &gt; 0</code></td><td>实验触发用表达式</td></tr><tr><td>告警级别</td><td><code>二级告警（Warning）</code></td><td>当前按 S2 处理</td></tr><tr><td>执行频率</td><td><code>@every 60s</code></td><td>每 60 秒计算一次</td></tr><tr><td>持续时长</td><td><code>60</code></td><td>条件持续 60 秒后触发</td></tr><tr><td>标签</td><td><code>env=lab</code></td><td>事件过滤和通知匹配会用到</td></tr></tbody></table><p><img src="`+l+'" alt="N9E 告警规则配置"></p><p>保存后验证：</p><p>规则保存后回到 <code>告警 -&gt; 规则管理</code>，确认规则处于启用状态。等待一次执行周期后进入 <code>告警 -&gt; 告警事件</code>，能看到规则生成的事件。</p><p>排错入口：</p><p>规则不触发时，先在规则页点击 <code>数据预览</code>，确认 PromQL 有结果；再检查数据源是否绑定到 <code>VictoriaMetrics</code>、告警引擎集群是否为 <code>default</code>、持续时长是否还没满足。</p><p>这里之前踩过一个坑：规则导入时如果只带 PromQL，没有绑定数据源筛选，列表里能看到规则，但告警引擎不会真正查到后端数据。N9E v8 里要确认 <code>datasource_queries</code> 或页面上的数据源选择已经落到规则里。现象是规则存在、启用状态正常，但 <code>告警事件</code> 一直没有记录。</p><h2 id="七、告警事件" tabindex="-1">七、告警事件 <a class="header-anchor" href="#七、告警事件" aria-label="Permalink to &quot;七、告警事件&quot;">​</a></h2><p>事件查看入口如下：</p><p><code>告警 -&gt; 告警事件 -&gt; 活跃告警 -&gt; 告警详情</code> （英文含义：Alerting -&gt; Alert events -&gt; Active alerts -&gt; Alert detail）</p><p>操作步骤：</p><ol><li>进入 <code>告警 -&gt; 告警事件</code>。</li><li>在 <code>活跃告警</code> 列表里找到 <code>实验-节点CPU使用率触发</code>。</li><li>点击事件名称或详情入口。</li><li>在详情弹窗里查看状态、级别、标签、触发值、PromQL 和执行频率。</li></ol><p>验证重点：</p><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th><th>用途</th></tr></thead><tbody><tr><td>事件状态</td><td><code>Triggered</code></td><td>表示规则仍在触发</td></tr><tr><td>告警级别</td><td><code>S2（Warning）</code></td><td>和规则里的级别对应</td></tr><tr><td>触发值</td><td><code>0.75</code></td><td>当前查询结果值</td></tr><tr><td>事件标签</td><td><code>ident=node12</code>、<code>env=lab</code>、<code>cpu=cpu-total</code></td><td>定位机器和通知匹配</td></tr><tr><td>PromQL</td><td><code>cpu_usage_active{ident=&quot;node12&quot;} &gt; 0</code></td><td>回看触发条件</td></tr></tbody></table><p><img src="'+n+'" alt="N9E 告警事件详情"></p><p>排错入口：</p><p>事件列表没有记录时，回到规则页看 <code>数据预览</code> 和执行周期；事件存在但通知没发时，再查 <code>通知 -&gt; 通知规则</code>、通知媒介和接收组。</p><p>告警排查时，<code>ident</code>、<code>env</code>、<code>region</code>、<code>__name__</code> 和触发值通常是第一组定位信息。只有规则名没有标签，后续排查会很慢；尤其是主机类告警，<code>ident</code> 基本就是定位入口。</p><h2 id="八、通知入口" tabindex="-1">八、通知入口 <a class="header-anchor" href="#八、通知入口" aria-label="Permalink to &quot;八、通知入口&quot;">​</a></h2><p>通知链路分成两层：通知媒介和通知规则。</p><table tabindex="0"><thead><tr><th>对象</th><th>说明</th></tr></thead><tbody><tr><td>通知媒介</td><td>邮件、钉钉、飞书、企业微信、Webhook 等发送通道</td></tr><tr><td>通知规则</td><td>哪些事件发给哪些接收组，是否按标签过滤</td></tr><tr><td>告警接收组</td><td>用户组或值班组，决定谁收到消息</td></tr><tr><td>重复通知间隔</td><td>告警持续未恢复时多久重复发送</td></tr><tr><td>恢复通知</td><td>告警恢复后是否发送恢复消息</td></tr></tbody></table><p>当前实验没有接外部机器人，空的通知媒介页面不能说明通知链路可用。真正配置通知时，最少要验证一次完整链路：告警事件生成、通知规则匹配、媒介发送成功、接收端能看到机器名和触发值。</p><h2 id="九、常见问题" tabindex="-1">九、常见问题 <a class="header-anchor" href="#九、常见问题" aria-label="Permalink to &quot;九、常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th><th>处理方向</th></tr></thead><tbody><tr><td>数据源列表正常，但查询无数据</td><td>URL 对 N9E 容器不可达，或时间范围不对</td><td>在 N9E 所在机器用 <code>curl</code> 查 VictoriaMetrics，再回页面选数据源</td></tr><tr><td>Dashboard 导入后是空的</td><td>模板采集器和实际采集器不一致</td><td>Categraf 用 Categraf 模板，Node Exporter 用 Node Exporter 模板</td></tr><tr><td><code>ident</code> 变量为空</td><td>指标里没有 <code>ident</code> 标签</td><td>检查 Categraf <code>hostname</code>、全局标签和上报数据</td></tr><tr><td>告警规则存在但不触发</td><td>数据源没绑定、PromQL 无结果、告警引擎没工作</td><td>查规则里的数据源筛选、PromQL 预览、告警引擎集群</td></tr><tr><td>有告警事件但没有通知</td><td>通知规则没匹配、媒介未配置、接收组为空</td><td>查通知规则过滤条件、通知媒介连通性、用户联系方式</td></tr><tr><td>告警太多</td><td>标签维度过细，或每个 CPU 核心都触发</td><td>PromQL 加 <code>cpu=&quot;cpu-total&quot;</code>，必要时按 <code>ident</code> 聚合</td></tr></tbody></table><p>N9E 平台操作是否可用，可以沿着一条事件链回看：事件里看到规则名和标签，规则里看到 PromQL 和数据源，Dashboard 里能看到同一台机器的指标，后端时序库里也能查到同一条时间序列。</p>',115)])])}const _=d(h,[["render",b]]);export{P as __pageData,_ as default};
